      safe1_h3: "\ud83d\udd12 \ub85c\uce5c \uc800\uc7a5",
      safe1_p: "\uc990\uaca8\ucc3e\uae30\uc640 \uc124\uc815\uc740 \uae30\uae30\uc5d0\ub9cc \uc800\uc7a5\ub429\ub2c8\ub2e4. \uc678\ubd80 \uc11c\ubc84\uc5d0\ub294 \uc77c\uc808 \uc804\uc1a1\ud558\uc9c0 \uc54a\uc2b5\ub2c8\ub2e4.",
      safe2_h3: "\ud83e\udd16 AI\uc5d0\ub294 \uc9c0\uc5ed \uc774\ub984\ub9cc \uc804\uc1a1",
      safe2_p: "\uc774\ubca4\ud2b8 \uc218\uc9d1\uc744 \uc704\ud574 AI\uc5d0 \uc804\uc1a1\ub418\ub294 \uac83\uc740 \uac80\uc0c9 \uc9c0\uc5ed \uc774\ub984\ubfd0\uc785\ub2c8\ub2e4. \uac1c\uc778\uc815\ubcf4\ub294 \uc804\uc1a1\ub418\uc9c0 \uc54a\uc2b5\ub2c8\ub2e4.",
      safe3_h3: "\ud83d\uddd1\ufe0f \uc644\uc804 \uc0ad\uc81c",
