      faq_tag: "FAQ",
      faq_h2: "\uc790\uc8fc \ubb3b\ub294 \uc9c8\ubb38",
      faq1_q: "\uc815\ub9d0 \ubb34\ub8cc\uc778\uac00\uc694?",
      faq1_a: "\ub124, \uc644\uc804 \ubb34\ub8cc\uc785\ub2c8\ub2e4. Google \uacc4\uc815\uc73c\ub85c \ub85c\uadf8\uc778\ud558\uae30\ub9cc \ud558\uba74 \ub429\ub2c8\ub2e4. \ud558\ub8e8 \ucd5c\ub300 5\ubc88 \uc774\ubca4\ud2b8\ub97c \uc218\uc9d1\ud560 \uc218 \uc788\uc2b5\ub2c8\ub2e4.",
      faq2_q: "\uc5b4\ub5a4 \uc9c0\uc5ed\uc758 \uc774\ubca4\ud2b8\ub97c \ucc3e\uc744 \uc218 \uc788\ub098\uc694?",
      faq2_a: "\uc804 \uc138\uacc4 \uc5b4\ub5a4 \uc9c0\uc5ed\uc774\ub4e0 \uc9c0\uc815\ud560 \uc218 \uc788\uc2b5\ub2c8\ub2e4. \ucd5c\ub300 5\uac1c \uc9c0\uc5ed\uc744 \ub4f1\ub85d\ud560 \uc218 \uc788\uc2b5\ub2c8\ub2e4. \uc9c0\uc5ed \uc774\ub984\uc740 \uc5b8\uc81c\ub4e0\uc9c0 \ubcc0\uacbd \uac00\ub2a5\ud569\ub2c8\ub2e4.",
      faq3_q: "\uac1c\uc778\uc815\ubcf4\ub294 \uc548\uc804\ud55c\uac00\uc694?",
      faq3_a: "\uc990\uaca8\ucc3e\uae30\uc640 \uc124\uc815\uc740 \ubaa8\ub450 \uae30\uae30\uc5d0 \uc800\uc7a5\ub429\ub2c8\ub2e4. AI\uc5d0 \uc804\uc1a1\ub418\ub294 \uac83\uc740 \uac80\uc0c9 \uc9c0\uc5ed \uc774\ub984\ubfd0\uc774\uba70 \uac1c\uc778\uc815\ubcf4\ub294 \uc804\uc1a1\ub418\uc9c0 \uc54a\uc2b5\ub2c8\ub2e4.",
      faq4_q: "\uce98\ub9b0\ub354 \ub3d9\uae30\ud654\uc5d0 \ud544\uc694\ud55c \uac83\uc740?",
      faq4_a: "\uce98\ub9b0\ub354 \uc77d\uae30/\uc4f0\uae30 \uad8c\ud55c\uc774 \ud544\uc694\ud569\ub2c8\ub2e4. \uc124\uc815\uc5d0\uc11c \ub300\uc0c1 \uce98\ub9b0\ub354\ub97c \uc120\ud0dd\ud558\uace0 \uc54c\ub9bc \uc2dc\uac04\uc744 \ub9de\ucda4 \uc124\uc815\ud560 \uc218 \uc788\uc2b5\ub2c8\ub2e4.",
      faq5_q: "\uc544\uc774\ud3f0\uc5d0\uc11c\ub3c4 \uc0ac\uc6a9\ud560 \uc218 \uc788\ub098\uc694?",
      faq5_a: "\ud604\uc7ac Android \uc804\uc6a9\uc785\ub2c8\ub2e4. Android 8.0(API 26) \uc774\uc0c1\uc758 \uae30\uae30\uc5d0\uc11c \uc774\uc6a9 \uac00\ub2a5\ud569\ub2c8\ub2e4.",
      faq6_q: "\uce74\ud14c\uace0\ub9ac\ub97c \ub9de\ucda4 \uc124\uc815\ud560 \uc218 \uc788\ub098\uc694?",
