      flow2_p: "\u064a\u0628\u062d\u062b \u0627\u0644\u0630\u0643\u0627\u0621 \u0627\u0644\u0627\u0635\u0637\u0646\u0627\u0639\u064a \u0641\u064a \u0627\u0644\u0648\u064a\u0628 \u0648\u064a\u062c\u0645\u0639 \u0627\u0644\u0641\u0639\u0627\u0644\u064a\u0627\u062a \u0644\u0644\u0640 14 \u064a\u0648\u0645\u064b\u0627 \u0627\u0644\u0642\u0627\u062f\u0645\u0629",
      flow3_h3: "\u062a\u0635\u0641\u062d \u0628\u0627\u0644\u0642\u0627\u0626\u0645\u0629 \u0623\u0648 \u0627\u0644\u062e\u0631\u064a\u0637\u0629",
      flow3_p: "\u0627\u0633\u062a\u0639\u0631\u0636 \u0627\u0644\u0641\u0639\u0627\u0644\u064a\u0627\u062a \u0641\u064a \u0642\u0627\u0626\u0645\u0629 \u0623\u0648 \u062e\u0631\u064a\u0637\u0629",
