      map_tag: "\u0639\u0631\u0636 \u0627\u0644\u062e\u0631\u064a\u0637\u0629",
      map_h3: "\u0627\u0644\u0641\u0639\u0627\u0644\u064a\u0627\u062a<br>\u0639\u0644\u0649 \u0627\u0644\u062e\u0631\u064a\u0637\u0629.",
