      map_f3: "\u0627\u0644\u0627\u062a\u062c\u0627\u0647\u0627\u062a \u0639\u0628\u0631 \u062a\u0637\u0628\u064a\u0642 Maps",
      filter_tag: "\u0641\u0644\u062a\u0631 \u0630\u0643\u064a",
      filter_h3: "\u0627\u0628\u062d\u062b \u0639\u0646 \u0627\u0644\u0641\u0639\u0627\u0644\u064a\u0627\u062a<br>\u0627\u0644\u062a\u064a \u062a\u0631\u064a\u062f\u0647\u0627.",
      filter_p: "15 \u0641\u0626\u0629\u060c \u0641\u0644\u0627\u062a\u0631 \u0627\u0644\u062a\u0627\u0631\u064a\u062e\u060c \u0627\u0644\u0645\u062c\u0627\u0646\u064a\u0629 \u0641\u0642\u0637\u060c \u0627\u0644\u0645\u0641\u0636\u0644\u0629 \u2014 \u0627\u0628\u062d\u062b \u0639\u0646 \u0627\u0644\u0641\u0639\u0627\u0644\u064a\u0629 \u0627\u0644\u0645\u062b\u0627\u0644\u064a\u0629 \u0641\u064a \u062b\u0648\u0627\u0646.",
      filter_f1: "15 \u0641\u0626\u0629: \u0645\u0648\u0633\u064a\u0642\u0649\u060c \u0637\u0639\u0627\u0645\u060c \u0631\u064a\u0627\u0636\u0629 \u0648\u0627\u0644\u0645\u0632\u064a\u062f",
