      filter_f3: "\u0625\u0638\u0647\u0627\u0631 \u0627\u0644\u0641\u0639\u0627\u0644\u064a\u0627\u062a \u0627\u0644\u0645\u062c\u0627\u0646\u064a\u0629 \u0641\u0642\u0637",
      cal_tag: "\u0645\u0632\u0627\u0645\u0646\u0629 \u0627\u0644\u062a\u0642\u0648\u064a\u0645",
      cal_h3: "\u0644\u0627 \u062a\u0641\u0648\u0651\u062a\u0643<br>\u0623\u064a \u0641\u0639\u0627\u0644\u064a\u0629.",
      cal_p: "\u0623\u0636\u0641 \u0625\u0644\u0649 \u0627\u0644\u0645\u0641\u0636\u0644\u0629 \u0648\u0633\u064a\u062a\u0632\u0627\u0645\u0646 \u062a\u0644\u0642\u0627\u0626\u064a\u064b\u0627 \u0645\u0639 Google Calendar. \u0627\u062d\u0635\u0644 \u0639\u0644\u0649 \u062a\u0630\u0643\u064a\u0631\u0627\u062a \u0642\u0628\u0644 \u0627\u0644\u0628\u062f\u0621 \u0645\u0628\u0627\u0634\u0631\u0629.",
