      cal_f3: "\u0625\u0632\u0627\u0644\u0629 \u0627\u0644\u0645\u0641\u0636\u0644\u0629 \u062a\u062d\u0630\u0641 \u0623\u064a\u0636\u064b\u0627 \u0645\u0646 \u0627\u0644\u062a\u0642\u0648\u064a\u0645",
      lang_tag: "\u0627\u0644\u0644\u063a\u0627\u062a \u0648\u0627\u0644\u0633\u0645\u0627\u062a",
      lang_h3: "11 \u0644\u063a\u0629.<br>\u0633\u0645\u0627\u062a \u062f\u0627\u0643\u0646\u0629 \u0648\u0641\u0627\u062a\u062d\u0629.",
      lang_p: "\u064a\u062f\u0639\u0645 11 \u0644\u063a\u0629 \u0628\u0645\u0627 \u0641\u064a\u0647\u0627 \u0627\u0644\u0625\u0646\u062c\u0644\u064a\u0632\u064a\u0629 \u0648\u0627\u0644\u064a\u0627\u0628\u0627\u0646\u064a\u0629 \u0648\u0627\u0644\u0635\u064a\u0646\u064a\u0629 \u0648\u0627\u0644\u0643\u0648\u0631\u064a\u0629 \u0648\u0627\u0644\u0639\u0631\u0628\u064a\u0629. \u062a\u062a\u0643\u064a\u0641 \u0648\u0627\u062c\u0647\u0629 \u0627\u0644\u0645\u0633\u062a\u062e\u062f\u0645 \u0648\u062c\u0645\u0639 \u0627\u0644\u0641\u0639\u0627\u0644\u064a\u0627\u062a \u062a\u0644\u0642\u0627\u0626\u064a\u064b\u0627.",
      lang_f1: "\u062a\u0628\u062f\u064a\u0644 \u0627\u0644\u0644\u063a\u0629 \u0627\u0644\u062a\u0644\u0642\u0627\u0626\u064a \u0644\u0640 11 \u0644\u063a\u0629",
      lang_f2: "\u0633\u0645\u0629 \u062f\u0627\u0643\u0646\u0629 / \u0641\u0627\u062a\u062d\u0629 / \u0646\u0638\u0627\u0645",
      lang_f3: "\u0641\u0639\u0627\u0644\u064a\u0627\u062a \u062a\u064f\u062c\u0645\u0639 \u0628\u0644\u063a\u062a\u0643",
      features_tag: "\u0627\u0644\u0645\u064a\u0632\u0627\u062a",
