      feat1_h3: "\u0627\u0644\u062c\u0645\u0639 \u0627\u0644\u062a\u0644\u0642\u0627\u0626\u064a \u0628\u0627\u0644\u0630\u0643\u0627\u0621 \u0627\u0644\u0627\u0635\u0637\u0646\u0627\u0639\u064a",
