      feat2_h3: "\u0639\u0631\u0636 \u0627\u0644\u062e\u0631\u064a\u0637\u0629 \u0648\u0627\u0644\u0642\u0627\u0626\u0645\u0629",
      feat2_p: "\u0639\u0644\u0627\u0645\u0627\u062a \u0639\u0644\u0649 Google Maps \u0623\u0648 \u0642\u0627\u0626\u0645\u0629 \u0628\u0637\u0627\u0642\u0627\u062a. \u0628\u0637\u0627\u0642\u0627\u062a \u0645\u0639\u0627\u064a\u0646\u0629 \u0645\u062f\u0631\u062c\u0629.",
