      feat5_h3: "11 \u0644\u063a\u0629",
      feat5_p: "\u0625\u0646\u062c\u0644\u064a\u0632\u064a\u0629\u060c \u064a\u0627\u0628\u0627\u0646\u064a\u0629\u060c \u0635\u064a\u0646\u064a\u0629\u060c \u0643\u0648\u0631\u064a\u0629 \u0648\u0627\u0644\u0645\u0632\u064a\u062f. \u062a\u062a\u0643\u064a\u0641 \u0627\u0644\u0648\u0627\u062c\u0647\u0629 \u0648\u0627\u0644\u062c\u0645\u0639 \u062a\u0644\u0642\u0627\u0626\u064a\u064b\u0627.",
      feat6_h3: "\u0627\u0644\u0648\u0636\u0639 \u0627\u0644\u062f\u0627\u0643\u0646",
      feat6_p: "\u0641\u0627\u062a\u062d / \u062f\u0627\u0643\u0646 / \u062a\u0644\u0642\u0627\u0626\u064a (\u0627\u0644\u0646\u0638\u0627\u0645). \u062a\u0635\u0645\u064a\u0645 \u0645\u0631\u064a\u062d \u0644\u0644\u0639\u064a\u0646\u064a\u0646 \u0644\u0627\u0633\u062a\u062e\u062f\u0627\u0645 \u0645\u0631\u064a\u062d.",
      safety_tag: "\u0627\u0644\u062e\u0635\u0648\u0635\u064a\u0629 \u0648\u0627\u0644\u0623\u0645\u0627\u0646",
