      safety_lead: "\u0645\u0635\u0645\u0645 \u0628\u0627\u0644\u062e\u0635\u0648\u0635\u064a\u0629 \u0623\u0648\u0644\u0627\u064b \u062d\u062a\u0649 \u062a\u062a\u0645\u0643\u0646 \u0645\u0646 \u0627\u0633\u062a\u062e\u062f\u0627\u0645\u0647 \u0628\u062b\u0642\u0629.",
      safe1_h3: "\ud83d\udd12 \u0627\u0644\u062a\u062e\u0632\u064a\u0646 \u0627\u0644\u0645\u062d\u0644\u064a",
      safe1_p: "\u062a\u064f\u062d\u0641\u0638 \u0627\u0644\u0645\u0641\u0636\u0644\u0629 \u0648\u0627\u0644\u0625\u0639\u062f\u0627\u062f\u0627\u062a \u0639\u0644\u0649 \u0627\u0644\u062c\u0647\u0627\u0632 \u0641\u0642\u0637. \u0644\u0627 \u0634\u064a\u0621 \u064a\u064f\u0631\u0633\u0644 \u0625\u0644\u0649 \u062e\u0648\u0627\u062f\u0645 \u062e\u0627\u0631\u062c\u064a\u0629.",
      safe2_h3: "\ud83e\udd16 \u0623\u0633\u0645\u0627\u0621 \u0627\u0644\u0645\u0646\u0627\u0637\u0642 \u0641\u0642\u0637 \u062a\u064f\u0631\u0633\u0644 \u0625\u0644\u0649 \u0627\u0644\u0630\u0643\u0627\u0621 \u0627\u0644\u0627\u0635\u0637\u0646\u0627\u0639\u064a",
      safe2_p: "\u0623\u0633\u0645\u0627\u0621 \u0645\u0646\u0627\u0637\u0642 \u0627\u0644\u0628\u062d\u062b \u0641\u0642\u0637 \u062a\u064f\u0631\u0633\u0644 \u0644\u062c\u0645\u0639 \u0627\u0644\u0641\u0639\u0627\u0644\u064a\u0627\u062a. \u0644\u0627 \u062a\u064f\u0646\u0642\u0644 \u0623\u064a \u0645\u0639\u0644\u0648\u0645\u0627\u062a \u0634\u062e\u0635\u064a\u0629.",
      safe3_h3: "\ud83d\uddd1\ufe0f \u0627\u0644\u062d\u0630\u0641 \u0627\u0644\u0643\u0627\u0645\u0644",
      safe3_p: "\u0623\u0644\u063a \u0627\u0644\u062a\u062b\u0628\u064a\u062a \u0648\u0633\u062a\u064f\u062d\u0630\u0641 \u062c\u0645\u064a\u0639 \u0627\u0644\u0628\u064a\u0627\u0646\u0627\u062a. \u0644\u0627 \u062a\u0628\u0642\u0649 \u0623\u064a \u0628\u064a\u0627\u0646\u0627\u062a.",
